#include<bits/stdc++.h>
using namespace std;
vector<int> v[1000005];
int n, m, k, a[100005], b[100005], ans[100005], pos, cnt, s, x;

int main() {
	cin >> m >> n >> k;
	for (int i = 1; i <= n; i++) {
		cin >> a[i];
	}
	for (int i = 1; i <= n; i++) {
		cin >> b[i];
	}
	for (int i = 1; i <= n; i++) {
		v[a[i]].push_back(b[i]);
	}
	for (int i = 1; i <= m; i++) {
		sort(v[i].begin(), v[i].end(), greater<int>());

	}
	/*for (int i = 1; i <= m; i++) {
		cout<<i<<":";
			for (int j = 0; j < v[i].size(); j++) {
					cout<<v[i][j]<<" ";
				}
				cout<<endl;
		}
	*/while (1) {
		s = 0;
		for (int i = 1; i <= m; i++) {
			if (ans[i] >= k) {
				s++;
				continue;
			}
			if (pos >= v[i].size()) {
				s = -1;
				break;
			}
			if (x == i) {
				s = -2;
				break;
			}
			x = i, ans[i] += v[i][pos], cnt++;
		}
		pos++;
		if (s == -1) break;
		if (s == m) break;
		if (s == -2) break;
	}
	if (s == -1) {cnt = -1;}
	if (s == -2) {
		pos -= 2, cnt--, ans[x] -= v[x][pos];
		int q = v[x].size() - pos;
		int p = n - cnt - q + 1;
		p = min(p, q);
		while (p-- && ans[x] < k) {
			cnt += 2;
		}
		if (ans[x] < k) {
			cnt = -1;
		} else {
			cnt--;
		}

	}
	cout << cnt;
	return 0;
}
